import React from 'react';

const InventoryItem = ({ item, onUpdate }) => {
    return (
        <div className="product-row">
            <div className="product-info">
                <div className="product-name">{item.name}</div>
                <div className="product-expiry">
                    Срок: {item.expiry || 'Без срока'}
                </div>
            </div>

            <div className="counter-group">
                <button className="count-btn" onClick={() => onUpdate(item.name, -1)}>-</button>
                <span style={{minWidth: '20px', fontWeight: 'bold'}}>{item.count}</span>
                <button className="count-btn" onClick={() => onUpdate(item.name, 1)}>+</button>
            </div>
        </div>
    );
};

export default InventoryItem;
